import{_ as e,o as t,c as d,ag as r}from"./chunks/framework.BbyMWZAR.js";const u=JSON.parse('{"title":"CommonJS 与 ESM 的区别","description":"","frontmatter":{"title":"CommonJS 与 ESM 的区别","difficulty":"easy","tags":["CommonJS","ESM","模块系统"],"estimate":10},"headers":[],"relativePath":"domains/nodejs/qa/qa-02-module-system.md","filePath":"domains/nodejs/qa/qa-02-module-system.md","lastUpdated":1783504823000}'),s={name:"domains/nodejs/qa/qa-02-module-system.md"};function c(a,o,l,i,n,m){return t(),d("div",null,[...o[0]||(o[0]=[r('<h1 id="问答-02-入门-commonjs-与-esm-的区别" tabindex="-1">问答 02（入门）：CommonJS 与 ESM 的区别 <a class="header-anchor" href="#问答-02-入门-commonjs-与-esm-的区别" aria-label="Permalink to &quot;问答 02（入门）：CommonJS 与 ESM 的区别&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>Node.js 中的模块系统有哪些？CommonJS（CJS）和 ES Modules（ESM）有什么区别？如何在项目中选择和互操作？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>两种模块系统</strong></p><ul><li><strong>CommonJS（CJS）</strong>：Node 传统方案，用 <code>require()</code> 导入、<code>module.exports</code> / <code>exports</code> 导出。</li><li><strong>ES Modules（ESM）</strong>：ECMAScript 标准方案，用 <code>import</code> / <code>export</code>。</li></ul><p><strong>核心区别</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>CommonJS</th><th>ESM</th></tr></thead><tbody><tr><td>语法</td><td><code>require</code> / <code>module.exports</code></td><td><code>import</code> / <code>export</code></td></tr><tr><td>加载时机</td><td>运行时同步加载</td><td>编译期静态分析、异步加载</td></tr><tr><td>导入值</td><td>值的拷贝（对象引用拷贝）</td><td>只读的动态绑定（live binding）</td></tr><tr><td>this</td><td><code>module.exports</code></td><td><code>undefined</code></td></tr><tr><td>顶层 await</td><td>不支持</td><td>支持</td></tr><tr><td>文件后缀/标识</td><td><code>.cjs</code> 或默认</td><td><code>.mjs</code> 或 <code>package.json</code> 中 <code>&quot;type&quot;:&quot;module&quot;</code></td></tr><tr><td>Tree-shaking</td><td>难</td><td>易（静态结构）</td></tr></tbody></table><p><strong>如何启用 ESM</strong></p><ul><li>文件用 <code>.mjs</code>；或在 <code>package.json</code> 里加 <code>&quot;type&quot;: &quot;module&quot;</code>（此时 <code>.js</code> 按 ESM 解析，CJS 用 <code>.cjs</code>）。</li></ul><p><strong>互操作</strong></p><ul><li>ESM 里可以 <code>import cjs from &#39;cjs-module&#39;</code>（默认导入拿到 <code>module.exports</code>）。</li><li>CJS 里 <strong>不能直接 <code>require</code> 一个 ESM</strong>（ESM 是异步的），需用动态 <code>import()</code>（返回 Promise）。</li></ul><p><strong>选择建议</strong></p><ul><li>新项目、面向未来、需要 tree-shaking：优先 ESM。</li><li>老项目、大量依赖仅 CJS、需要 <code>require</code> 动态路径：可继续 CJS 或逐步迁移。</li></ul><h2 id="追问-1-exports-和-module-exports-有什么区别-为什么-exports-无效" tabindex="-1">追问 1：<code>exports</code> 和 <code>module.exports</code> 有什么区别？为什么 <code>exports = {...}</code> 无效？ <a class="header-anchor" href="#追问-1-exports-和-module-exports-有什么区别-为什么-exports-无效" aria-label="Permalink to &quot;追问 1：`exports` 和 `module.exports` 有什么区别？为什么 `exports = {...}` 无效？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>模块初始时 <code>exports === module.exports</code>，二者指向同一个对象。真正被导出的是 <code>module.exports</code>。</li><li><code>exports.foo = 1</code> 有效，因为它是在共享对象上加属性。</li><li><code>exports = {...}</code> 只是让局部变量 <code>exports</code> 指向新对象，<strong>切断了与 <code>module.exports</code> 的引用</strong>，所以导出的仍是原来的空对象，无效。</li><li>想整体替换必须写 <code>module.exports = {...}</code>。</li></ul><h2 id="追问-2-esm-的-live-binding-和-cjs-的值拷贝-有什么实际影响" tabindex="-1">追问 2：ESM 的 live binding 和 CJS 的值拷贝，有什么实际影响？ <a class="header-anchor" href="#追问-2-esm-的-live-binding-和-cjs-的值拷贝-有什么实际影响" aria-label="Permalink to &quot;追问 2：ESM 的 live binding 和 CJS 的值拷贝，有什么实际影响？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>CJS</strong>：<code>const { count } = require(&#39;./m&#39;)</code> 拿到的是导入那一刻的值拷贝，模块内部后续改变 <code>count</code>，导入方不会跟着变（除非导出的是对象并改其属性）。</li><li><strong>ESM</strong>：<code>import { count } from &#39;./m&#39;</code> 是对导出变量的只读动态引用，模块内部改变 <code>count</code>，导入方读到的会是<strong>更新后的值</strong>。</li><li>影响：ESM 更适合表达「实时状态」，但导入方不能给它赋值（只读）；写共享计数器等场景两者行为不同，迁移时要注意。</li></ul><h2 id="追问-3-import-动态导入有什么用-和静态-import-相比适合什么场景" tabindex="-1">追问 3：<code>import()</code> 动态导入有什么用？和静态 <code>import</code> 相比适合什么场景？ <a class="header-anchor" href="#追问-3-import-动态导入有什么用-和静态-import-相比适合什么场景" aria-label="Permalink to &quot;追问 3：`import()` 动态导入有什么用？和静态 `import` 相比适合什么场景？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><code>import()</code> 返回一个 Promise，可在运行时按条件、按需加载模块（代码分割、懒加载、根据配置加载插件）。</li><li>它是在 CJS 中加载 ESM 的唯一方式。</li><li>静态 <code>import</code> 在编译期确定依赖，利于 tree-shaking 和打包分析，但路径必须是字面量、只能在模块顶层。</li><li>场景：路由级懒加载、可选依赖、根据环境变量选择实现、减小启动体积时用动态 <code>import()</code>。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/nodejs/RESOURCES">Node.js 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://nodejs.org/api/modules.html" target="_blank" rel="noreferrer">Node.js: Modules</a>：CommonJS <code>require</code>、<code>module.exports</code> 与互操作细节。</li><li><a href="https://nodejs.org/api/esm.html" target="_blank" rel="noreferrer">Node.js: ESM</a>：ES Module 在 Node 中的解析、静态分析与 top-level await。</li><li><a href="https://nodejs.org/api/packages.html" target="_blank" rel="noreferrer">Node.js: Packages</a>：<code>&quot;type&quot;: &quot;module&quot;</code> 与 <code>.mjs</code>/<code>.cjs</code> 后缀约定。</li></ul>',26)])])}const h=e(s,[["render",c]]);export{u as __pageData,h as default};
